    console.log(reduc_arr);//["red","blue","green"]
```

***我们都知道 面向对象 有封装，继承，多态三个特性，在JavaScript中同样如此，
通过对象参生实例 实现工厂化生产 可以节省很多资源***

## ES6实现对象继承
通过es6新语法class创建对象，extends实现继承
```
    //定义Car类
    class Car{
        constructor(name,type){//Car类的属性
            this.name = name;
            this.type = type;
        }
        //定义一个Car类介绍自己的方法
        talk(){
            return this.name+"是一辆"+this.type
        }
    }
    class smallCar extends Car{//定义smallCar 继承自Car类
        constructor(name,type){
            //传递需要继承的属性值
            super(name,type);
        }
    }
    //创建 bmw实例
    var bmw = new smallCar("宝马X5","suv");
    //使用 bmw实例中的属性与方法
    console.log(bmw.name);//"宝马X5"
    console.log(bmw.type);//"suv"
    console.log(bmw.talk());//"宝马X5是一辆suv"
```
在上述例子中，通过Class产生 Car类对象，通过smallCar类extens函数继承Car类的共有属性与方法，通过super()方法 传递smallCar实例的各属性值，在**没有属性值需要继承时 也需要super()方法进行声明**super()方法 与extens 是相辅相成 不可分割的。
## ES5 通过原型对象实现继承
通过构造函数,原型对象prototype, constructor改变原型指向实现继承
```
    //1.编写父构造函数
    function Father(name,age) {
        //父构造函数属性
        this.name = name;
        this.age = age;
    }
    //2.为父构造函数添加talk公有方法
    Father.prototype.talk = function () {
        return "我是"+this.name+",今年"+this.age+"岁！"
    }
    //3.子构造函数
    function Son(name,age) {
        //3.1通过call方法将子构造函数中的this对象传递过去，
        // 改变父构造函数的this指向产生继承类似super() 但只继承了属性
        Father.call(this,name,age);
    }
    //4. 将 子构造函数的原型对象指向一个 父构造函数实例
    // 通过__proto__共享 Father构造函数的原型对象  但是改变了 Son.prototype的指向
    //在一个正常的构造函数中 constructor应该指向自己的原型对象prototype
    Son.prototype = new Father();
    console.log(Son.prototype.constructor);//指向了Father 这是不对的 需要改变指向 指向Son构造函数的原型对象

    //5.重新改变 子构造函数的原型对象的指向
    Son.prototype.constructor = Son;

    //6.新建Son的实例
    var son = new Son("儿子","5")
    console.log(son.name);//儿子
    console.log(son.age);//5
    console.log(son.talk());//我是儿子,今年5岁！
    //继承了父构造函数的方法  实现继承
```
在ES5中实现对象继承要难很多，需要通过 call()方法 传递子原型 this对象来继承属性，通过父原型对象 覆盖 子原型对象来产生 方法 继承
但是父原型对象覆盖子原型对象 会连同子原型对象的constructor属性
所以需要重新改变子原型对象的指向
而ES6通过Class 和 Surper 解决了这些指向问题，使用更加简单

MDN对闭包的定义是：函数与对其状态即词法环境（lexical environment）的引用共同构成闭包（closure）。也就是说，**闭包可以让你从内部函数访问外部函数作用域**。在JavaScript，函数在每次创建时生成闭包。
闭包：内部函数总是可以访问其所在的外部函数中声明的参数和变量，即使在其外部函数被返回（寿命终结）了之后。
通俗来讲  **一个内部函数访问外部函数局部作用域内的变量** 就产生了闭包
作用：**延申变量的作用范围 ，使局部变量常驻在内存中不被销毁**
缺点：**变量不被销毁，发生内存泄漏**

#### 我们先通过一个错误的例子了解局部作用域和垃圾回收机制
```
    function func() {
        var num = 10;
	console.log(num);	
    }
    func();//输出10
    console.log(num);//报错 num is not defined
```
结论：在一个函数的外部无法访问函数内部作用域定义的变量 即函数的局部作用域。而在函数内部，func函数后 1.定义变量 2.被console.log 输出  3.被调用之后 退出函数 变量i失去引用 转而被当垃圾回收。 
在javascript中，如果一个对象不再被引用，那么这个对象就会被垃圾回收机制回收；
#### 再来看一个简单的闭包案例
```
   // 内部函数总是可以访问其所在的外部函数中声明的参数和变量，即使在其外部函数被返回（寿命终结）了之后。
    function fn() {
        var str = "这是一段字符！";
        return function () {
            return str;
        }
    }
    let f =fn();
    console.log(f());//输出字符串 被返回的方法外部访问了fn函数局部作用域内的变量str 产生了闭包
    // f = "这是一段字符！";
    // f()函数称为 闭包函数
```
闭包函数：声明在一个函数中的函数，叫做闭包函数。
结论：被当作返回值的方法f 在fn()方法的局部作用域中访问了str变量产生了闭包，同时我们在fn()函数外部通过变量 f 函数接收了返回值，**f = str**,成功访问了函数局部作用域内的srt变量； 变相的 srt变量也延申了其值到全局；
#### 两个案例了解闭包的作用
定义一个数组 三秒后打印其内容
var arr = [11,22,33];
```
//1.常规方法
   for (var i = 0;i<arr.length;i++){
        setTimeout(()=>{
            console.log(arr[i]);//打印输出
        },3000)
   }
//
```
结果：报错   
undefined*3
原因：for循环是同步函数，而timeout的回调函数是一个异步函数，for循环执行完成之后， 其中的变量 i 已经被后续for循环的i++操作重新赋值 现在的值为3，导致报错。
解决方案：通过闭包 对每次for循环产生变量i值进行引用 产生闭包作用域 保留变量存活状态 但是内存中增加了 i=0,i=1,i=2;四个值 产生内存溢出。
```
//2.采用闭包方式
   for (var i = 0;i<arr.length;i++){
	//通过for循环 产生4个立即函数 并将i值传入 产生引用关系
        (function (i) {
            setTimeout(()=>{
                console.log(arr[i]);//打印输出
            },3000)
        })(i)
	//Timeout中的回调方法访问了立即函数中的变量 i 产生闭包
    }
```
结果：
[0,1,2,3]
正常输出，延申变量i的使用范围 产生闭包
####  下面再来看一个经典案例
