  function flatten (data, keys, level = 0) {
        return data.reduce((arr, x) => [
            ...arr,
            keys.reduce((o, k) => (o[k] = x[k], o), {level}),
            ...flatten(x.children || [], keys, level + 1),
        ], [])
    }

