获取成功，解决跨域。

2.  JSONP 是服务器与客户端跨源通信的常用方法。最大特点就是简单适用，兼容性好（兼容低版本IE），缺点是只支持get请求，不支持post请求。其原理是利用script标签不受同源策略的限制，可以自由加载各类文件的特点去实现的；

请求配置
````
    //创建一个script标签
    let scriptTag = document.createElement("script");
    //注入请求地址  可带参数
    scriptTag.src = "http://localhost:2222/?callback=callback";
    //将创建script标签放入head中 发送请求
    document.querySelector('head').appendChild(scriptTag);
    //回调函数
    function callback(res) {
        console.log(res)
    }
````
服务端配置
````
let http = require('http');
let url = require('url');
let querystring = require('querystring');
//导入url querystring模块，解析请求参数
http.createServer((req,res)=>{
    //获取参数
    let query = querystring.parse(url.parse(req.url).query);
    //回调函数名称
    let callback = query.callback;
    console.log(callback);
    res.writeHead(200,{
        //返回数据格式一定要为js
        "Content-Type":"text/javascript;charset=UTF-8"
    });
    let data = { //定义返回数据
        code:200,
        msg:"这是一段文字！"
    };
    //发送数据包
    res.end(`${callback}(${JSON.stringify(data)})`)
}).listen(2222);
console.log("success 2222");

````
