> 节流函数

在js开发中经常遇到事件频发触发的问题，例如监听屏幕上下滑动，频繁触发，这样会导致性能损耗，节流函数则可以缓解这个问题，通过节流函数，可以让时间在一定时间内，只响应一次，避免频繁触发。
![在这里插入图片描述](https://img-blog.csdnimg.cn/20200316034850579.png)
原理如上图，原本我们在每个时间段都会触发一次方法，通过节流函数，在60ms内仅对第一次触发响应。
### 方法一 利用timeout延时器
```
    let jieLiu = (func,delay = 50) => {
        let timer = null;//保持timer
        return function() {
            if(!timer){//若timer = null 才触发
                func.call(this);//调用方法，并将指向纠正
                timer = setTimeout(()=>{
                   timer = null;//设置定时器 在delay时间内仅第一次调用生效
                },delay)
            }
        }
    };
```
通过闭包函数，保存timer状态，重复调用，通过timer状态判断是否应该执行方法
### 方法二 利用时间戳
```
    let jieLiu = (func,delay = 50) => {
        let timer = 0;//初始化timer
        return function() {
            if( new Date() - timer >= delay){//判断当前时间距离上次执行是否小于规定
                func.call(this);//调用方法，并将指向纠正
                timer = new Date();//为timer重新赋值 记录最新执行时间
            }
        }
    };
```
原理一致，延时时间改为时间戳判断

> 防抖函数
> 
在开发中还会遇到一种情况，某一事件触发，一段时间内 只需要最后一次触发响应，例如表单验证，搜索功能，监听表单的改变，一定时间间隔内只监听最后一次表单改变，显示相关推荐信息，节省性能消耗。
![在这里插入图片描述](https://img-blog.csdnimg.cn/20200316140430374.png)
如上图，一事件在1 2 步是分别触发事件但响应间隔小于要求，不响应，在第三步触发后，在规定事件内未再次触发，则响应事件。
 ```

     let throTtle = (func,delay = 100) => {
        let timer = null;
        return function () {
            clearTimeout(timer);//清除定时器 重新记时
            timer = setTimeout(func.bind(this),delay);//达到规定休眠时间，响事件
        }
    };


 ```
 只有大于100ms时间间隔的时间会响应

##### 网页图片过多导致加载缓慢，这个时候可以使用懒加载的方式，利用img标签在src为空时不会加载资源的特性，当图片在浏览器窗口内显示时，再加载。
```
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <meta http-equiv="X-UA-Compatible" content="ie=edge">
    <title>Document</title>
    <style>
        .container{
            display: flex;
            justify-content: space-between;
            width: 600px;
            margin: 0 auto;
            flex-wrap: wrap;
        }
        .container img{
            width: 49%;
            height: 100%;
            margin-bottom: 10px;
        }
        img[src=""]{
            background-color: pink;
        }
    </style>
</head>
<body>
<div class="container">
    <!--    <img src="" alt="1" data-src="test.jpg">-->
</div>
<script>
    //通过script标签同步加载特性批量添加内容
    let container = document.querySelector(".container");
    let img = `<img src="" alt="1" data-src="https://www.mrdiv.top/static/img/p2.f4999c4.jpg">`;
    for (let i = 0;i<60;i++){
        container.insertAdjacentHTML("beforeEnd",img)
    }
</script>

<script>
    window.onload = function () {
        lazyLoad();
    };
    document.onscroll = throtte(function () {
        lazyLoad();
    });
    function lazyLoad() {
        let imgs = document.body.querySelectorAll("img");
        let wHeight = window.innerHeight;
        let sHeight =  document.documentElement.scrollTop;
        imgs.forEach(item=>{
            //判断图片是否在视窗内
            if(item.offsetTop<wHeight+sHeight){
                item.src = item.getAttribute("data-src")
            }
        })
    }
    //节流函数，防止触发过渡频繁
    function throtte(func,delay = 300) {
        let timer = null;
        return function () {
            let args = arguments;
            if(!timer){
                func.apply(this,args);
                timer = setTimeout(()=>{
                    timer = null;
                },delay)
            }
        }
    }
</script>
</body>
</html>

```

