### 三、多接口并发统一处理
由于axios基于promise开发，所以promise.all()，Promise.race()同样适用。
```
var p1 = new Promise((resolve, reject) => {
          this.$axios.get(url).then(res=>{
              resolve(res)
          }).catch(err=>{
              reject(err)
          })
      });

      var p2 = new Promise(async (resolve,reject)=>{
           resolve(await this.$axios.get(url));
      })

    // 请求都完成后执行
    // 调用Promise.all().then(res=>{})
      Promise.all([p1,p2]).then(res=>{
          console.log(res);
      })
    }

    // 有一个请求完成即执行
    // 调用Promise.race().then(res=>{})
      Promise.race([p1,p2]).then(res=>{
          console.log(res);
      })
    }
```
### 四、全局拦截器
在**请求，响应**被 then 或 catch 处理前拦截它们，比如添加其它全局请求数据(token,签名)，集中处理catch报错，判断请求是否成功，避免分开处理。
1. 向服务器发出请求前拦截处理
```
// 添加请求拦截器
axios.interceptors.request.use( (config) => {
    // 在发送请求之前做些什么

    return config;
  },  (error) => {
    // 对请求错误做些什么

    return Promise.reject(error);
  });


```
2. 被服务器响应后拦截处理
```
// 添加响应拦截器
axios.interceptors.response.use( (res) => {
    // 对响应数据做点什么

    return res;
  }, (error) => {
    // 对响应错误做点什么

    return Promise.reject(error);
  });
```
