### 四、Vue数据响应原理
- Object.defineProperty实现数据劫持
- 通过defineReactive value实现中间变量，完成数据变更
```
    <h1 id="app">{{msg}}</h1>
    <script>
      let data = {
        name: "张三",
        age: 18,
        obj: {
          num: 123,
        },
        arr: [{ name: "arr" }],
      };
      // 数据响应绑定  通过value作为value的中间变量，保存在闭包中
      function defineReactive(target, key, value, enumerable) {
        // 深度遍历  添加响应式绑定
        if (typeof value === "object" && value !== null) {
          reactfy(value);
        }
        // 数据响应劫持
        Object.defineProperty(target, key, {
          enumerable: !!enumerable,
          get() {
            return value;
          },
          set(newValue) {
            value = newValue;
	    // 模拟视图更新   在完整源码中应该用watcher进行更新
            document.querySelector("#app").innerHTML = value;
          },
        });
      }
      function reactfy(o) {
        if (Array.isArray(o)) {
          o.forEach((item) => reactfy(item));
        } else if (o instanceof Object) {
          Object.keys(o).forEach((key) => {
            defineReactive(o, key, o[key], true);
          });
        }
      }
      reactfy(data);
    </script>
```

