### 一、MySql事务
sql事务，保证所有sql执行成功，避免出现断档
```
    const client = app.mysql.get('default');
    const conn = await client.beginTransaction();

    try {
      // 1.执行SQL
      await conn.select('process'{ where: { batchId: item } });
      await conn.select('process'{ where: { batchId: item } });
      await conn.select('process'{ where: { batchId: item } });
      return await conn.commit();
    } catch (err) {
      // 2.执行出错，撤销操作
